     1→/**
     2→ * Diagram Editor Store
     3→ * Manages editor state (tool, selection, clipboard, undo/redo)
     4→ */
     5→
     6→import { create } from 'zustand';
     7→import type { DiagramElement, ToolType, HistoryEntry, CanvasState, AlignmentType } from '../types/diagrams';
     8→
     9→interface DiagramEditorState {
    10→  // Current tool
    11→  currentTool: ToolType;
    12→  setCurrentTool: (tool: ToolType) => void;
    13→
    14→  // P0: Shape palette state
    15→  shapePaletteOpen: boolean;
    16→  toggleShapePalette: () => void;
    17→
    18→  // Selection
    19→  selectedElementIds: string[];
    20→  selectElement: (id: string, addToSelection?: boolean) => void;
    21→  selectMultiple: (ids: string[]) => void;
    22→  clearSelection: () => void;
    23→  isSelected: (id: string) => boolean;
    24→
    25→  // Clipboard
    26→  clipboard: DiagramElement[];
    27→  copy: (elements: DiagramElement[]) => void;
    28→  paste: () => DiagramElement[];
    29→
    30→  // Drawing state
    31→  isDragging: boolean;
    32→  isDrawing: boolean;
    33→  setIsDragging: (dragging: boolean) => void;
    34→  setIsDrawing: (drawing: boolean) => void;
    35→
    36→  // P0: Grouping (receives elements + callback to update diagram)
    37→  groupElements: (elements: DiagramElement[], onUpdate: (updates: DiagramElement[]) => void) => string;
    38→  ungroupElements: (elements: DiagramElement[], groupId: string, onUpdate: (updates: DiagramElement[]) => void) => void;
    39→  getGroupId: (elementId: string, elements: DiagramElement[]) => string | undefined;
    40→
    41→  // P0: Alignment (receives elements + callback to update diagram)
    42→  alignElements: (
    43→    elementIds: string[],
    44→    elements: DiagramElement[],
    45→    type: AlignmentType,
    46→    onUpdate: (updates: DiagramElement[]) => void
    47→  ) => void;
    48→
    49→  // Undo/Redo
    50→  history: HistoryEntry[];
    51→  currentHistoryIndex: number;
    52→  maxHistorySize: number;
    53→  pushHistory: (elements: DiagramElement[], canvasState: CanvasState) => void;
    54→  undo: () => HistoryEntry | undefined;
    55→  redo: () => HistoryEntry | undefined;
    56→  canUndo: () => boolean;
    57→  canRedo: () => boolean;
    58→}
    59→
    60→export const useDiagramEditorStore = create<DiagramEditorState>((set, get) => ({
    61→  // Tool
    62→  currentTool: 'select',
    63→  setCurrentTool: (tool) => set({ currentTool: tool }),
    64→
    65→  // P0: Shape palette
    66→  shapePaletteOpen: true,
    67→  toggleShapePalette: () => set((state) => ({ shapePaletteOpen: !state.shapePaletteOpen })),
    68→
    69→  // Selection
    70→  selectedElementIds: [],
    71→
    72→  selectElement: (id, addToSelection = false) => {
    73→    set((state) => {
    74→      if (addToSelection) {
    75→        // Toggle selection
    76→        const isCurrentlySelected = state.selectedElementIds.includes(id);
    77→        return {
    78→          selectedElementIds: isCurrentlySelected
    79→            ? state.selectedElementIds.filter((sid) => sid !== id)
    80→            : [...state.selectedElementIds, id],
    81→        };
    82→      } else {
    83→        return { selectedElementIds: [id] };
    84→      }
    85→    });
    86→  },
    87→
    88→  selectMultiple: (ids) => set({ selectedElementIds: ids }),
    89→
    90→  clearSelection: () => set({ selectedElementIds: [] }),
    91→
    92→  isSelected: (id) => get().selectedElementIds.includes(id),
    93→
    94→  // Clipboard
    95→  clipboard: [],
    96→
    97→  copy: (elements) => {
    98→    set({ clipboard: elements.map((el) => ({ ...el })) });
    99→  },
   100→
   101→  paste: () => {
   102→    const { clipboard } = get();
   103→    if (clipboard.length === 0) return [];
   104→
   105→    // Create new elements with new IDs and offset position
   106→    const pastedElements = clipboard.map((el) => ({
   107→      ...el,
   108→      id: crypto.randomUUID(),
   109→      x: el.x + 20, // Offset by 20px
   110→      y: el.y + 20,
   111→    }));
   112→
   113→    return pastedElements;
   114→  },
   115→
   116→  // Drawing state
   117→  isDragging: false,
   118→  isDrawing: false,
   119→  setIsDragging: (dragging) => set({ isDragging: dragging }),
   120→  setIsDrawing: (drawing) => set({ isDrawing: drawing }),
   121→
   122→  // P0: Grouping
   123→  groupElements: (elements, onUpdate) => {
   124→    const { selectedElementIds } = get();
   125→    const groupId = crypto.randomUUID();
   126→
   127→    // Assign groupId to selected elements
   128→    const updatedElements = elements.map((el) =>
   129→      selectedElementIds.includes(el.id) ? { ...el, groupId } : el
   130→    );
   131→
   132→    onUpdate(updatedElements);
   133→    return groupId;
   134→  },
   135→
   136→  ungroupElements: (elements, groupId, onUpdate) => {
   137→    // Remove groupId from elements in the group
   138→    const updatedElements = elements.map((el) =>
   139→      el.groupId === groupId ? { ...el, groupId: undefined } : el
   140→    );
   141→
   142→    onUpdate(updatedElements);
   143→  },
   144→
   145→  getGroupId: (elementId, elements) => {
   146→    const element = elements.find((el) => el.id === elementId);
   147→    return element?.groupId;
   148→  },
   149→
   150→  // P0: Alignment
   151→  alignElements: (elementIds, elements, type, onUpdate) => {
   152→    const selectedElements = elements.filter((el) => elementIds.includes(el.id));
   153→    if (selectedElements.length < 2) return;
   154→
   155→    // Calculate bounding box for alignment reference
   156→    const getBounds = (el: DiagramElement) => {
   157→      const rotation = el.rotation || 0;
   158→      if (rotation === 0) {
   159→        return {
   160→          left: el.x,
   161→          right: el.x + el.width,
   162→          top: el.y,
   163→          bottom: el.y + el.height,
   164→          centerX: el.x + el.width / 2,
   165→          centerY: el.y + el.height / 2,
   166→        };
   167→      }
   168→
   169→      // For rotated shapes, use the center point
   170→      return {
   171→        left: el.x,
   172→        right: el.x + el.width,
   173→        top: el.y,
   174→        bottom: el.y + el.height,
   175→        centerX: el.x + el.width / 2,
   176→        centerY: el.y + el.height / 2,
   177→      };
   178→    };
   179→
   180→    const bounds = selectedElements.map((el) => ({
   181→      element: el,
   182→      bounds: getBounds(el),
   183→    }));
   184→
   185→    let updatedElements = [...elements];
   186→
   187→    switch (type) {
   188→      case 'left': {
   189→        const leftmost = Math.min(...bounds.map((b) => b.bounds.left));
   190→        updatedElements = elements.map((el) => {
   191→          const bound = bounds.find((b) => b.element.id === el.id);
   192→          return bound ? { ...el, x: leftmost } : el;
   193→        });
   194→        break;
   195→      }
   196→
   197→      case 'center': {
   198→        const centerX =
   199→          bounds.reduce((sum, b) => sum + b.bounds.centerX, 0) / bounds.length;
   200→        updatedElements = elements.map((el) => {
   201→          const bound = bounds.find((b) => b.element.id === el.id);
   202→          return bound ? { ...el, x: centerX - el.width / 2 } : el;
   203→        });
   204→        break;
   205→      }
   206→
   207→      case 'right': {
   208→        const rightmost = Math.max(...bounds.map((b) => b.bounds.right));
   209→        updatedElements = elements.map((el) => {
   210→          const bound = bounds.find((b) => b.element.id === el.id);
   211→          return bound ? { ...el, x: rightmost - el.width } : el;
   212→        });
   213→        break;
   214→      }
   215→
   216→      case 'top': {
   217→        const topmost = Math.min(...bounds.map((b) => b.bounds.top));
   218→        updatedElements = elements.map((el) => {
   219→          const bound = bounds.find((b) => b.element.id === el.id);
   220→          return bound ? { ...el, y: topmost } : el;
   221→        });
   222→        break;
   223→      }
   224→
   225→      case 'middle': {
   226→        const centerY =
   227→          bounds.reduce((sum, b) => sum + b.bounds.centerY, 0) / bounds.length;
   228→        updatedElements = elements.map((el) => {
   229→          const bound = bounds.find((b) => b.element.id === el.id);
   230→          return bound ? { ...el, y: centerY - el.height / 2 } : el;
   231→        });
   232→        break;
   233→      }
   234→
   235→      case 'bottom': {
   236→        const bottommost = Math.max(...bounds.map((b) => b.bounds.bottom));
   237→        updatedElements = elements.map((el) => {
   238→          const bound = bounds.find((b) => b.element.id === el.id);
   239→          return bound ? { ...el, y: bottommost - el.height } : el;
   240→        });
   241→        break;
   242→      }
   243→
   244→      case 'distribute': {
   245→        // Determine orientation based on variance
   246→        const xVariance = Math.max(...bounds.map((b) => b.bounds.centerX)) - Math.min(...bounds.map((b) => b.bounds.centerX));
   247→        const yVariance = Math.max(...bounds.map((b) => b.bounds.centerY)) - Math.min(...bounds.map((b) => b.bounds.centerY));
   248→
   249→        if (xVariance > yVariance) {
   250→          // Distribute horizontally
   251→          const sorted = [...bounds].sort((a, b) => a.bounds.centerX - b.bounds.centerX);
   252→          const first = sorted[0].bounds.centerX;
   253→          const last = sorted[sorted.length - 1].bounds.centerX;
   254→          const spacing = (last - first) / (sorted.length - 1);
   255→
   256→          updatedElements = elements.map((el) => {
   257→            const index = sorted.findIndex((s) => s.element.id === el.id);
   258→            if (index === -1) return el;
   259→            const newCenterX = first + spacing * index;
   260→            return { ...el, x: newCenterX - el.width / 2 };
   261→          });
   262→        } else {
   263→          // Distribute vertically
   264→          const sorted = [...bounds].sort((a, b) => a.bounds.centerY - b.bounds.centerY);
   265→          const first = sorted[0].bounds.centerY;
   266→          const last = sorted[sorted.length - 1].bounds.centerY;
   267→          const spacing = (last - first) / (sorted.length - 1);
   268→
   269→          updatedElements = elements.map((el) => {
   270→            const index = sorted.findIndex((s) => s.element.id === el.id);
   271→            if (index === -1) return el;
   272→            const newCenterY = first + spacing * index;
   273→            return { ...el, y: newCenterY - el.height / 2 };
   274→          });
   275→        }
   276→        break;
   277→      }
   278→    }
   279→
   280→    onUpdate(updatedElements);
   281→  },
   282→
   283→  // Undo/Redo
   284→  history: [],
   285→  currentHistoryIndex: -1,
   286→  maxHistorySize: 50,
   287→
   288→  pushHistory: (elements, canvasState) => {
   289→    set((state) => {
   290→      // Remove any redo history (everything after current index)
   291→      const newHistory = state.history.slice(0, state.currentHistoryIndex + 1);
   292→
   293→      // Add new entry
   294→      newHistory.push({
   295→        elements: elements.map((el) => ({ ...el })), // Deep clone
   296→        canvasState: { ...canvasState },
   297→      });
   298→
   299→      // Limit history size
   300→      if (newHistory.length > state.maxHistorySize) {
   301→        newHistory.shift();
   302→        return {
   303→          history: newHistory,
   304→          currentHistoryIndex: newHistory.length - 1,
   305→        };
   306→      }
   307→
   308→      return {
   309→        history: newHistory,
   310→        currentHistoryIndex: newHistory.length - 1,
   311→      };
   312→    });
   313→  },
   314→
   315→  undo: () => {
   316→    const { history, currentHistoryIndex } = get();
   317→    if (currentHistoryIndex <= 0) return undefined;
   318→
   319→    const newIndex = currentHistoryIndex - 1;
   320→    set({ currentHistoryIndex: newIndex });
   321→    return history[newIndex];
   322→  },
   323→
   324→  redo: () => {
   325→    const { history, currentHistoryIndex } = get();
   326→    if (currentHistoryIndex >= history.length - 1) return undefined;
   327→
   328→    const newIndex = currentHistoryIndex + 1;
   329→    set({ currentHistoryIndex: newIndex });
   330→    return history[newIndex];
   331→  },
   332→
   333→  canUndo: () => {
   334→    const { currentHistoryIndex } = get();
   335→    return currentHistoryIndex > 0;
   336→  },
   337→
   338→  canRedo: () => {
   339→    const { history, currentHistoryIndex } = get();
   340→    return currentHistoryIndex < history.length - 1;
   341→  },
   342→}));
   343→

