   333→          {...styleProps}
   334→          points={[
   335→            0,
   336→            0,
   337→            element.endPoint ? element.endPoint.x - element.x : element.width,
   338→            element.endPoint ? element.endPoint.y - element.y : element.height,
   339→          ]}
   340→        />
   341→      );
   342→
   343→    case 'arrow':
   344→      return (
   345→        <Arrow
   346→          {...commonProps}
   347→          {...styleProps}
   348→          points={[
   349→            0,
   350→            0,
   351→            element.endPoint ? element.endPoint.x - element.x : element.width,
   352→            element.endPoint ? element.endPoint.y - element.y : element.height,
   353→          ]}
   354→          pointerLength={10}
   355→          pointerWidth={10}
   356→        />
   357→      );
   358→
   359→    default:
