    57→    }
    58→
    59→    const foundDiagram = getDiagram(id);
    60→    if (!foundDiagram) {
    61→      navigate('/diagrams');
    62→      return;
    63→    }
    64→
    65→    setDiagram(foundDiagram);
    66→    setTitle(foundDiagram.title);
    67→  }, [id, getDiagram, navigate]);
    68→
    69→  // Update canvas size on window resize
    70→  useEffect(() => {
    71→    const updateSize = () => {
    72→      if (canvasContainerRef.current) {
    73→        setCanvasSize({
    74→          width: canvasContainerRef.current.clientWidth,
    75→          height: canvasContainerRef.current.clientHeight,
    76→        });
    77→      }
    78→    };
