    86→  useEffect(() => {
    87→    if (!diagram) return;
    88→
    89→    const handleKeyDown = (e: KeyboardEvent) => {
    90→      const selectedElementIds = useDiagramEditorStore.getState().selectedElementIds;
    91→      const clearSelection = useDiagramEditorStore.getState().clearSelection;
    92→      const copy = useDiagramEditorStore.getState().copy;
    93→      const paste = useDiagramEditorStore.getState().paste;
    94→      const undo = useDiagramEditorStore.getState().undo;
    95→      const redo = useDiagramEditorStore.getState().redo;
    96→      const canUndo = useDiagramEditorStore.getState().canUndo();
    97→      const canRedo = useDiagramEditorStore.getState().canRedo();
    98→      const groupElements = useDiagramEditorStore.getState().groupElements;
    99→      const ungroupElements = useDiagramEditorStore.getState().ungroupElements;
   100→      const getGroupId = useDiagramEditorStore.getState().getGroupId;
   101→
   102→      // Delete selected elements
   103→      if (e.key === 'Delete' && selectedElementIds.length > 0) {
   104→        const updatedElements = diagram.elements.filter(
   105→          (el) => !selectedElementIds.includes(el.id)
   106→        );
   107→        updateDiagram(diagram.id, { elements: updatedElements });
   108→        setDiagram({ ...diagram, elements: updatedElements });
   109→        clearSelection();
   110→      }
   111→
   112→      // Copy (Ctrl+C)
   113→      if (e.ctrlKey && e.key === 'c' && selectedElementIds.length > 0) {
   114→        const selectedElements = diagram.elements.filter((el) =>
   115→          selectedElementIds.includes(el.id)
   116→        );
   117→        copy(selectedElements);
   118→      }
   119→
   120→      // Paste (Ctrl+V)
   121→      if (e.ctrlKey && e.key === 'v') {
   122→        const pastedElements = paste();
   123→        if (pastedElements.length > 0) {
   124→          const updatedElements = [...diagram.elements, ...pastedElements];
   125→          updateDiagram(diagram.id, { elements: updatedElements });
   126→          setDiagram({ ...diagram, elements: updatedElements });
   127→        }
   128→      }
   129→
   130→      // Group (Ctrl+G)
   131→      if (e.ctrlKey && e.key === 'g' && !e.shiftKey && selectedElementIds.length >= 2) {
   132→        e.preventDefault();
   133→        groupElements(diagram.elements, (updatedElements) => {
   134→          updateDiagram(diagram.id, { elements: updatedElements });
   135→          setDiagram({ ...diagram, elements: updatedElements });
   136→        });
   137→      }
   138→
   139→      // Ungroup (Ctrl+Shift+G)
   140→      if (e.ctrlKey && e.shiftKey && e.key === 'G' && selectedElementIds.length > 0) {
   141→        e.preventDefault();
   142→        const firstGroupId = getGroupId(selectedElementIds[0], diagram.elements);
   143→        if (firstGroupId) {
   144→          ungroupElements(diagram.elements, firstGroupId, (updatedElements) => {
   145→            updateDiagram(diagram.id, { elements: updatedElements });
   146→            setDiagram({ ...diagram, elements: updatedElements });
   147→          });
   148→        }
   149→      }
   150→
   151→      // Undo (Ctrl+Z)
   152→      if (e.ctrlKey && e.key === 'z' && !e.shiftKey && canUndo) {
   153→        const historyEntry = undo();
   154→        if (historyEntry) {
   155→          updateDiagram(diagram.id, {
   156→            elements: historyEntry.elements,
   157→            canvasState: historyEntry.canvasState,
   158→          });
   159→          setDiagram({
