   231→        clearTimeout(autoSaveTimerRef.current);
   232→      }
   233→    };
   234→  }, [diagram, title, handleSave]);
   235→
   236→  const handleBack = () => {
   237→    handleSave();
   238→    navigate('/diagrams');
   239→  };
   240→
   241→  const handleAddShape = useCallback(() => {
   242→    if (!diagram) return;
   243→
   244→    const newElement: DiagramElement = {
   245→      id: crypto.randomUUID(),
   246→      type: currentTool as DiagramElement['type'],
   247→      x: 100 + Math.random() * 100,
   248→      y: 100 + Math.random() * 100,
   249→      width: currentTool === 'text' ? 200 : 100,
   250→      height: currentTool === 'text' ? 50 : 100,
   251→      zIndex: diagram.elements.length,
   252→      fill: currentTool === 'text' ? 'transparent' : '#ffffff',
   253→      stroke: '#000000',
   254→      strokeWidth: 2,
