   286→        ...prev,
   287→        currentX: e.clientX,
   288→        currentY: e.clientY,
   289→      }));
   290→    };
   291→
   292→    const handleMouseUp = (e: MouseEvent) => {
   293→      if (!diagram || !dragState.shape || !canvasContainerRef.current) {
   294→        setDragState({
   295→          active: false,
   296→          shape: null,
   297→          startX: 0,
   298→          startY: 0,
