   322→          shapeId: dragState.shape.id,
   323→          pathData: dragState.shape.pathData,
   324→          x: canvasX - (dragState.shape.defaultProps.width || 100) / 2,
   325→          y: canvasY - (dragState.shape.defaultProps.height || 100) / 2,
   326→          zIndex: diagram.elements.length,
   327→        } as DiagramElement;
   328→
