   353→      window.removeEventListener('mouseup', handleMouseUp);
   354→    };
   355→  }, [dragState.active, dragState.shape, diagram, updateDiagram]);
   356→
   357→  if (!diagram) {
   358→    return (
   359→      <div className="flex items-center justify-center h-screen">
