   361→          Loading diagram...
   362→        </div>
   363→      </div>
   364→    );
   365→  }
   366→
   367→  return (
   368→    <StoreErrorBoundary storeName="diagrams">
   369→      <div className="flex flex-col h-screen bg-background-light dark:bg-background-dark">
   370→        {/* Top Bar */}
   371→        <header className="flex items-center justify-between px-4 py-3 border-b border-border-light dark:border-border-dark bg-surface-light dark:bg-surface-dark">
   372→          <div className="flex items-center gap-3">
   373→            <button
   374→              onClick={handleBack}
   375→              className="p-2 hover:bg-surface-hover-light dark:hover:bg-surface-hover-dark rounded-lg transition-colors"
   376→              aria-label="Back to diagrams"
   377→            >
   378→              <ArrowLeft className="w-5 h-5" />
   379→            </button>
   380→
   381→            <input
   382→              type="text"
   383→              value={title}
   384→              onChange={(e) => setTitle(e.target.value)}
   385→              onBlur={handleSave}
   386→              className="text-lg font-semibold bg-transparent border-none focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark rounded px-2 py-1"
   387→              placeholder="Untitled Diagram"
   388→            />
   389→
   390→            {isSaving && (
   391→              <span className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary">
   392→                Saving...
   393→              </span>
   394→            )}
   395→          </div>
   396→
   397→          <button
   398→            onClick={handleSave}
   399→            className="flex items-center gap-2 px-4 py-2 bg-primary-light dark:bg-primary-dark text-white rounded-lg hover:opacity-90 transition-opacity"
   400→          >
   401→            <Save className="w-4 h-4" />
   402→            Save
   403→          </button>
   404→        </header>
   405→
   406→        {/* Editor Area */}
   407→        <div className="flex-1 flex">
   408→          {/* Toolbar */}
   409→          <Toolbar
   410→            elements={diagram.elements}
   411→            onUpdateElements={(updatedElements) => {
   412→              updateDiagram(diagram.id, { elements: updatedElements });
   413→              setDiagram({ ...diagram, elements: updatedElements });
