   105→            </div>
   106→
   107→            {/* Create button */}
   108→            <button
   109→              onClick={handleCreateDiagram}
   110→              className="flex items-center gap-2 px-4 py-2 bg-primary-light dark:bg-primary-dark text-white rounded-lg hover:opacity-90 transition-opacity"
   111→            >
   112→              <Plus className="w-4 h-4" />
   113→              New Diagram
   114→            </button>
   115→          </div>
   116→        </header>
   117→
   118→        {/* Content */}
   119→        <div className="flex-1 overflow-y-auto p-6">
   120→          {sortedDiagrams.length === 0 ? (
   121→            // Empty state
   122→            <div className="flex flex-col items-center justify-center h-full text-center">
   123→              <div className="w-24 h-24 mb-4 rounded-full bg-surface-light dark:bg-surface-dark flex items-center justify-center">
   124→                <Grid3x3 className="w-12 h-12 text-text-light-tertiary dark:text-text-dark-tertiary" />
   125→              </div>
   126→              <h2 className="text-xl font-semibold text-text-light-primary dark:text-text-dark-primary mb-2">
   127→                {searchQuery ? 'No diagrams found' : 'No diagrams yet'}
   128→              </h2>
   129→              <p className="text-text-light-secondary dark:text-text-dark-secondary mb-6 max-w-md">
   130→                {searchQuery
   131→                  ? 'Try adjusting your search query'
   132→                  : 'Create your first diagram to visualize ideas, plan projects, or document workflows'}
   133→              </p>
   134→              {!searchQuery && (
   135→                <button
   136→                  onClick={handleCreateDiagram}
   137→                  className="flex items-center gap-2 px-6 py-3 bg-primary-light dark:bg-primary-dark text-white rounded-lg hover:opacity-90 transition-opacity"
   138→                >
   139→                  <Plus className="w-5 h-5" />
   140→                  Create Your First Diagram
   141→                </button>
   142→              )}
   143→            </div>
   144→          ) : viewMode === 'grid' ? (
   145→            // Grid view
   146→            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
   147→              {sortedDiagrams.map((diagram) => (
   148→                <DiagramCard
   149→                  key={diagram.id}
   150→                  diagram={diagram}
   151→                  onOpen={() => handleOpenDiagram(diagram.id)}
   152→                  onDelete={() => handleDeleteDiagram(diagram.id)}
   153→                  onDuplicate={() => handleDuplicateDiagram(diagram.id)}
   154→                />
   155→              ))}
   156→            </div>
   157→          ) : (
   158→            // List view
   159→            <div className="space-y-2">
   160→              {sortedDiagrams.map((diagram) => (
   161→                <DiagramListItem
   162→                  key={diagram.id}
   163→                  diagram={diagram}
   164→                  onOpen={() => handleOpenDiagram(diagram.id)}
   165→                  onDelete={() => handleDeleteDiagram(diagram.id)}
   166→                  onDuplicate={() => handleDuplicateDiagram(diagram.id)}
   167→                />
   168→              ))}
   169→            </div>
   170→          )}
   171→        </div>
   172→      </main>
   173→    </StoreErrorBoundary>
   174→  );
   175→}
   176→
   177→// Diagram Card Component (Grid View)
   178→interface DiagramCardProps {
   179→  diagram: {
   180→    id: string;
   181→    title: string;
   182→    updatedAt: Date;
   183→    thumbnail?: string;
   184→    elements: unknown[];
   185→  };
   186→  onOpen: () => void;
   187→  onDelete: () => void;
   188→  onDuplicate: () => void;
   189→}
   190→
   191→function DiagramCard({ diagram, onOpen, onDelete, onDuplicate }: DiagramCardProps) {
   192→  return (
   193→    <div
   194→      className="group bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg overflow-hidden hover:shadow-lg transition-shadow cursor-pointer"
   195→      onClick={onOpen}
   196→    >
   197→      {/* Thumbnail */}
   198→      <div className="aspect-video bg-background-light dark:bg-background-dark flex items-center justify-center">
   199→        {diagram.thumbnail ? (
   200→          <img src={diagram.thumbnail} alt={diagram.title} className="w-full h-full object-cover" />
   201→        ) : (
   202→          <div className="text-text-light-tertiary dark:text-text-dark-tertiary">
   203→            <Grid3x3 className="w-12 h-12" />
   204→          </div>
   205→        )}
   206→      </div>
   207→
   208→      {/* Info */}
   209→      <div className="p-3">
   210→        <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary truncate mb-1">
   211→          {diagram.title}
   212→        </h3>
   213→        <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
   214→          {diagram.elements.length} {diagram.elements.length === 1 ? 'element' : 'elements'} •{' '}
   215→          {new Date(diagram.updatedAt).toLocaleDateString()}
   216→        </p>
   217→
   218→        {/* Actions (show on hover) */}
   219→        <div className="mt-2 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
   220→          <button
   221→            onClick={(e) => {
   222→              e.stopPropagation();
   223→              onDuplicate();
   224→            }}
   225→            className="flex-1 px-2 py-1 text-xs bg-surface-hover-light dark:bg-surface-hover-dark rounded hover:bg-border-light dark:hover:bg-border-dark"
   226→          >
   227→            Duplicate
   228→          </button>
   229→          <button
   230→            onClick={(e) => {
   231→              e.stopPropagation();
   232→              onDelete();
   233→            }}
   234→            className="flex-1 px-2 py-1 text-xs bg-red-500/10 text-red-500 rounded hover:bg-red-500/20"
   235→          >
   236→            Delete
   237→          </button>
   238→        </div>
   239→      </div>
   240→    </div>
   241→  );
   242→}
   243→
   244→// Diagram List Item Component (List View)
   245→function DiagramListItem({ diagram, onOpen, onDelete, onDuplicate }: DiagramCardProps) {
   246→  return (
   247→    <div
   248→      className="flex items-center gap-4 p-3 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg hover:shadow-md transition-shadow cursor-pointer"
   249→      onClick={onOpen}
   250→    >
   251→      {/* Thumbnail */}
   252→      <div className="w-20 h-14 bg-background-light dark:bg-background-dark rounded flex items-center justify-center flex-shrink-0">
   253→        {diagram.thumbnail ? (
   254→          <img src={diagram.thumbnail} alt={diagram.title} className="w-full h-full object-cover rounded" />
   255→        ) : (
   256→          <Grid3x3 className="w-6 h-6 text-text-light-tertiary dark:text-text-dark-tertiary" />
   257→        )}
   258→      </div>
