        <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
          {diagram.elements.length} {diagram.elements.length === 1 ? 'element' : 'elements'} •{' '}
          {new Date(diagram.updatedAt).toLocaleDateString()}
        </p>

        {/* Actions (show on hover) */}
        <div className="mt-2 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
          <button
            onClick={(e) => {
              e.stopPropagation();
              onDuplicate();
            }}
            className="flex-1 px-2 py-1 text-xs bg-surface-hover-light dark:bg-surface-hover-dark rounded hover:bg-border-light dark:hover:bg-border-dark"
