          <Grid3x3 className="w-6 h-6 text-text-light-tertiary dark:text-text-dark-tertiary" />
        )}
      </div>

      {/* Info */}
      <div className="flex-1 min-w-0">
        <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary truncate">
          {diagram.title}
        </h3>
        <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
          {diagram.elements.length} elements • Updated {new Date(diagram.updatedAt).toLocaleDateString()}
        </p>
      </div>

      {/* Actions */}
      <div className="flex gap-2">
        <button
          onClick={(e) => {
            e.stopPropagation();
            onDuplicate();
          }}
          className="px-3 py-1 text-sm bg-surface-hover-light dark:bg-surface-hover-dark rounded hover:bg-border-light dark:hover:bg-border-dark"
        >
          Duplicate
        </button>
        <button
          onClick={(e) => {
            e.stopPropagation();
            onDelete();
          }}
          className="px-3 py-1 text-sm bg-red-500/10 text-red-500 rounded hover:bg-red-500/20"
        >
          Delete
        </button>
      </div>
    </div>
  );
}

