            <input
              type="text"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              onBlur={handleSave}
              className="text-lg font-semibold bg-transparent border-none focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark rounded px-2 py-1"
              placeholder="Untitled Diagram"
            />

