    x: element.x,
    y: element.y,
    rotation: element.rotation || 0,
    draggable,
    onClick,
    onDragEnd,
    onTransformEnd,
  };

  const styleProps = {
    fill: element.fill || 'transparent',
    stroke: element.stroke || '#000000',
    strokeWidth: element.strokeWidth || 2,
  };

