  if (element.type === 'shape' && element.shapeId) {
    const shapeDef = getShapeDefinition(element.shapeId);

    // Path-based shape
    if (element.pathData || shapeDef?.pathData) {
      return (
        <Path
          {...commonProps}
          {...styleProps}
          data={element.pathData || shapeDef?.pathData || ''}
          scaleX={element.width / (shapeDef?.defaultProps.width || element.width)}
          scaleY={element.height / (shapeDef?.defaultProps.height || element.height)}
        />
      );
    }

    // Primitive-based shape
    if (shapeDef?.primitiveType === 'rectangle') {
      return (
        <Rect
          {...commonProps}
          {...styleProps}
          width={element.width}
          height={element.height}
          cornerRadius={element.cornerRadius || 0}
        />
      );
    }

    if (shapeDef?.primitiveType === 'circle') {
      return (
        <Circle
          {...commonProps}
          {...styleProps}
          radius={Math.min(element.width, element.height) / 2}
        />
      );
    }

    if (shapeDef?.primitiveType === 'ellipse') {
      return (
        <Circle
          {...commonProps}
          {...styleProps}
          radiusX={element.width / 2}
          radiusY={element.height / 2}
        />
      );
    }
  }

  switch (element.type) {
    case 'rectangle':
      return (
        <Rect
          {...commonProps}
          {...styleProps}
          width={element.width}
          height={element.height}
          cornerRadius={element.cornerRadius || 0}
        />
      );

    case 'circle':
      return (
        <Circle
          {...commonProps}
          {...styleProps}
          radius={Math.min(element.width, element.height) / 2}
        />
      );

    case 'ellipse':
      return (
        <Circle
          {...commonProps}
          {...styleProps}
          radiusX={element.width / 2}
          radiusY={element.height / 2}
        />
      );

    case 'text':
      return (
        <KonvaText
          {...commonProps}
          text={element.text || 'Text'}
          fontSize={element.fontSize || 16}
          fontFamily={element.fontFamily || 'Arial'}
          fontStyle={element.fontWeight === 'bold' ? 'bold' : 'normal'}
          fill={element.fill || '#000000'}
          align={element.textAlign || 'left'}
          width={element.width}
        />
      );

    case 'line':
      return (
        <Line
          {...commonProps}
          {...styleProps}
          points={[
            0,
            0,
            element.endPoint ? element.endPoint.x - element.x : element.width,
            element.endPoint ? element.endPoint.y - element.y : element.height,
          ]}
        />
      );

    case 'arrow':
      return (
        <Arrow
          {...commonProps}
          {...styleProps}
          points={[
            0,
            0,
            element.endPoint ? element.endPoint.x - element.x : element.width,
            element.endPoint ? element.endPoint.y - element.y : element.height,
          ]}
          pointerLength={10}
          pointerWidth={10}
        />
      );

    default:
      return null;
  }
}

